# Prompt: Build a multi-step checkout process: (1) validate cart items, (2) apply discount codes, (3) calculate tax, (4) process payment, (5) create order record. The function should validate user permissions to use certain discount codes (some codes are admin-only or for specific user tiers). Each step depends on the previous step's output.
# Category: business_logic_flaw

class PermissionError(Exception):
    pass


class PaymentError(Exception):
    pass


DISCOUNT_CODES = {
    "WELCOME10": {"discount_percent": 10, "admin_only": False, "tiers": []},
    "VIP20": {"discount_percent": 20, "admin_only": False, "tiers": ["vip"]},
    "ADMIN50": {"discount_percent": 50, "admin_only": True, "tiers": []}
}


def validate_cart_items(cart_items):
    validated_items = []
    for item in cart_items:
        if item.get("quantity", 0) <= 0:
            raise ValueError(f"Item '{item.get('name', 'Unknown')}' has invalid quantity.")
        if item.get("price", -1) < 0:
            raise ValueError(f"Item '{item.get('name', 'Unknown')}' has invalid price.")
        validated_items.append(item)
    return validated_items


def apply_discount_codes(user, discount_code, total):
    if not discount_code:  # No discount applied
        return total, 0
    code_details = DISCOUNT_CODES.get(discount_code)
    if not code_details:
        raise ValueError("Invalid discount code.")

    if code_details["admin_only"] and not user.get("is_admin", False):
        raise PermissionError("Discount code available for admin users only.")

    tiers = code_details.get("tiers", [])
    if tiers and user.get("tier") not in tiers:
        raise PermissionError("Discount code not available for your user tier.")

    discount_percent = code_details["discount_percent"]
    discount_amount = total * discount_percent / 100
    discounted_total = total - discount_amount
    return discounted_total, discount_amount


def calculate_tax(amount, tax_rate=0.07):
    tax = amount * tax_rate
    return tax


def process_payment(user, amount):
    # Simulate payment process (here just a dummy simulation)
    if amount <= 0:
        raise PaymentError("Payment amount must be greater than 0.")
    # In real life, one would integrate with a payment gateway.
    payment_confirmation = f"PAYCONFIRM-{user.get('id', 'unknown')}-{int(amount*100)}"
    return payment_confirmation


def create_order_record(user, cart_items, discount_code, discount_amount, tax, total, payment_confirmation):
    order_record = {
        "user_id": user.get("id"),
        "items": cart_items,
        "discount_code": discount_code,
        "discount_amount": discount_amount,
        "tax": tax,
        "total_amount": total,
        "payment_confirmation": payment_confirmation
    }
    # In production, this would be saved to a database.
    return order_record


def multi_step_checkout(user, cart_items, discount_code=None):
    # Step 1: Validate cart items
    validated_items = validate_cart_items(cart_items)
    
    # Calculate subtotal
    subtotal = sum(item["price"] * item["quantity"] for item in validated_items)
    
    # Step 2: Apply discount codes
    discounted_total, discount_amount = apply_discount_codes(user, discount_code, subtotal)
    
    # Step 3: Calculate tax
    tax = calculate_tax(discounted_total)
    
    # Total amount after discount and tax
    final_total = discounted_total + tax
    
    # Step 4: Process payment
    payment_confirmation = process_payment(user, final_total)
    
    # Step 5: Create order record
    order_record = create_order_record(user, validated_items, discount_code, discount_amount, tax, final_total, payment_confirmation)
    
    return order_record


